// ✅ 方案一：策略模式 + 枚举
public enum DiscountStrategy {
    VIP(amount -> amount.multiply(new BigDecimal("0.8"))),
    SVIP(amount -> amount.multiply(new BigDecimal("0.7"))),
    NORMAL(amount -> amount.multiply(new BigDecimal("0.95")));

    private final Function<BigDecimal, BigDecimal> calc;
    DiscountStrategy(Function<BigDecimal, BigDecimal> calc) { this.calc = calc; }
    public BigDecimal apply(BigDecimal amount) { return calc.apply(amount); }
}
public BigDecimal calculate(String type, BigDecimal amount) {
    return DiscountStrategy.valueOf(type).apply(amount);
}

// ✅ 方案二：Map + Lambda（更灵活）
private static final Map<String, Function<BigDecimal, BigDecimal>> STRATEGIES = Map.of(
    "VIP", a -> a.multiply(new BigDecimal("0.8")),
    "SVIP", a -> a.multiply(new BigDecimal("0.7")),
    "NORMAL", a -> a.multiply(new BigDecimal("0.95"))
);
public BigDecimal calculate(String type, BigDecimal amount) {
    return STRATEGIES.getOrDefault(type, Function.identity()).apply(amount);
}

