@PostMapping("/order")
public Result createOrder(@RequestHeader("Idempotent-Token") String token) {
    if (!redis.del("idempotent:" + token)) {  // del 返回 false = key 不存在
        return Result.fail("请勿重复提交");
    }
    // 执行业务
    orderService.create();
    return Result.ok();
}

// 方案二：注解 + AOP
@Target(ElementType.METHOD)
@Retention(RetentionPolicy.RUNTIME)
public @interface Idempotent {
    String key() default "";
    int expireSeconds() default 5;
}

@Aspect
@Component
public class IdempotentAspect {
    @Autowired
    private StringRedisTemplate redis;

    @Around("@annotation(idempotent)")
    public Object around(ProceedingJoinPoint pjp, Idempotent idempotent) throws Throwable {
        HttpServletRequest request = ((ServletRequestAttributes)
            RequestContextHolder.currentRequestAttributes()).getRequest();
        String key = idempotent.key() + ":" + request.getHeader("Idempotent-Token");

        if (Boolean.FALSE.equals(redis.delete(key))) {
            return Result.fail("请勿重复提交");
        }
        return pjp.proceed();
    }
}

// 使用
@Idempotent(key = "order:create")
@PostMapping("/order")
public Result createOrder() { ... }
```

关键：Redis `del` 天然原子，`setnx` + `expire` 也可以但要保证原子性。

